package orchestration

import (
	"fmt"
	"sync"
	"time"
)

type ContainerState string

const (
	StatePending   ContainerState = "pending"
	StateRunning   ContainerState = "running"
	StateStopped   ContainerState = "stopped"
	StateFailed    ContainerState = "failed"
	StateCompleted ContainerState = "completed"
)

type Container struct {
	ID          string
	Image       string
	Replicas    int
	CPU         float64
	MemoryMB    int
	State       ContainerState
	NodeID      string
	CreatedAt   time.Time
	UpdatedAt   time.Time
}

type Node struct {
	ID            string
	Hostname      string
	CPUAvailable  float64
	MemoryAvailable int
	Containers    map[string]*Container
	Status        string
}

type ClusterManager struct {
	mu     sync.RWMutex
	nodes  map[string]*Node
	tasks  map[string]*Container
}

func NewClusterManager() *ClusterManager {
	return &ClusterManager{
		nodes: make(map[string]*Node),
		tasks: make(map[string]*Container),
	}
}

func (cm *ClusterManager) RegisterNode(node *Node) error {
	cm.mu.Lock()
	defer cm.mu.Unlock()

	if _, exists := cm.nodes[node.ID]; exists {
		return fmt.Errorf("node %s already registered", node.ID)
	}

	node.Containers = make(map[string]*Container)
	cm.nodes[node.ID] = node
	return nil
}

func (cm *ClusterManager) Schedule(container *Container) error {
	cm.mu.Lock()
	defer cm.mu.Unlock()

	bestNode := cm.findBestNode(container)
	if bestNode == nil {
		return fmt.Errorf("no suitable node found for container %s", container.ID)
	}

	container.State = StateRunning
	container.NodeID = bestNode.ID
	bestNode.Containers[container.ID] = container
	bestNode.CPUAvailable -= container.CPU
	bestNode.MemoryAvailable -= container.MemoryMB
	cm.tasks[container.ID] = container
	return nil
}

func (cm *ClusterManager) findBestNode(container *Container) *Node {
	var best *Node
	for _, node := range cm.nodes {
		if node.Status != "ready" {
			continue
		}
		if node.CPUAvailable >= container.CPU && node.MemoryAvailable >= container.MemoryMB {
			if best == nil || node.CPUAvailable < best.CPUAvailable {
				best = node
			}
		}
	}
	return best
}

func (cm *ClusterManager) GetClusterStatus() map[string]interface{} {
	cm.mu.RLock()
	defer cm.mu.RUnlock()

	totalNodes := len(cm.nodes)
	runningTasks := 0
	for _, task := range cm.tasks {
		if task.State == StateRunning {
			runningTasks++
		}
	}

	return map[string]interface{}{
		"total_nodes":    totalNodes,
		"running_tasks":  runningTasks,
		"total_tasks":    len(cm.tasks),
	}
}

package ledger

import (
	"crypto/sha256"
	"encoding/hex"
	"fmt"
	"time"
)

type Transaction struct {
	ID        string
	From      string
	To        string
	Amount    float64
	Timestamp time.Time
	PrevHash  string
	Hash      string
}

func (t *Transaction) CalculateHash() string {
	h := sha256.New()
	h.Write([]byte(t.ID + t.From + t.To + fmt.Sprintf("%.2f", t.Amount) + t.PrevHash + t.Timestamp.String()))
	return hex.EncodeToString(h.Sum(nil))
}

type Block struct {
	Index        int
	Timestamp    time.Time
	Transactions []Transaction
	PreviousHash string
	Hash         string
	Nonce        int
}

func (b *Block) CalculateHash() string {
	h := sha256.New()
	h.Write([]byte(fmt.Sprintf("%d", b.Index) + b.PreviousHash + b.Timestamp.String() + b.Hash))
	return hex.EncodeToString(h.Sum(nil))
}

type Blockchain struct {
	Chain []*Block
	Mutex sync.RWMutex
}

func NewBlockchain() *Blockchain {
	genesis := createGenesisBlock()
	return &Blockchain{Chain: []*Block{genesis}}
}

func (bc *Blockchain) AddBlock(newBlock *Block) error {
	bc.Mutex.Lock()
	defer bc.Mutex.Unlock()

	previousBlock := bc.Chain[len(bc.Chain)-1]
	newBlock.PreviousHash = previousBlock.Hash
	newBlock.Hash = newBlock.CalculateHash()

	if !bc.IsChainValid() {
		return fmt.Errorf("invalid chain")
	}

	bc.Chain = append(bc.Chain, newBlock)
	return nil
}

func (bc *Blockchain) IsChainValid() bool {
	for i := 1; i < len(bc.Chain); i++ {
		current := bc.Chain[i]
		previous := bc.Chain[i-1]

		if current.PreviousHash != previous.Hash {
			return false
		}
		if current.CalculateHash() != current.Hash {
			return false
		}
	}
	return true
}

func createGenesisBlock() *Block {
	return &Block{
		Index:   0,
		Timestamp: time.Now(),
		Hash:    "00000000000000000000000000000000",
	}
}

package mesh

import (
	"fmt"
	"sync"
	"time"
)

type ServiceEntry struct {
	Name      string
	Host      string
	Port      int
	Instances []Instance
	Health    string
}

type Instance struct {
	ID          string
	IP          string
	Port        int
	Healthy     bool
	LastChecked time.Time
	Requests    int
	Errors      int
}

type LoadBalancer interface {
	Select(instances []Instance) *Instance
}

type RoundRobinLB struct {
	counter int
	mu      sync.Mutex
}

func (rr *RoundRobinLB) Select(instances []Instance) *Instance {
	rr.mu.Lock()
	defer rr.mu.Unlock()

	healthy := filterHealthy(instances)
	if len(healthy) == 0 {
		return nil
	}

	idx := rr.counter % len(healthy)
	rr.counter++
	return &healthy[idx]
}

func filterHealthy(instances []Instance) []Instance {
	var healthy []Instance
	for _, inst := range instances {
		if inst.Healthy {
			healthy = append(healthy, inst)
		}
	}
	return healthy
}

type SidecarProxy struct {
	serviceName string
	lb          LoadBalancer
	registry    *ServiceRegistry
}

type ServiceRegistry struct {
	mu      sync.RWMutex
	services map[string]*ServiceEntry
}

func NewServiceRegistry() *ServiceRegistry {
	return &ServiceRegistry{services: make(map[string]*ServiceEntry)}
}

func (sr *ServiceRegistry) RegisterService(svc *ServiceEntry) {
	sr.mu.Lock()
	defer sr.mu.Unlock()
	sr.services[svc.Name] = svc
}

func (sr *ServiceRegistry) Discover(serviceName string) ([]Instance, error) {
	sr.mu.RLock()
	defer sr.mu.RUnlock()

	svc, ok := sr.services[serviceName]
	if !ok {
		return nil, fmt.Errorf("service %s not found", serviceName)
	}
	return svc.Instances, nil
}

func main() {
	registry := NewServiceRegistry()
	registry.RegisterService(&ServiceEntry{Name: "user-service", Instances: []Instance{
		{ID: "u1", IP: "10.0.0.1", Port: 8080, Healthy: true},
		{ID: "u2", IP: "10.0.0.2", Port: 8080, Healthy: true},
	}})

	proxy := &SidecarProxy{
		serviceName: "user-service",
		lb:          &RoundRobinLB{},
		registry:    registry,
	}
}

package cicd

import (
	"fmt"
	"time"
)

type StageStatus string

const (
	StagePending   StageStatus = "pending"
	StageRunning   StageStatus = "running"
	StagePassed    StageStatus = "passed"
	StageFailed    StageStatus = "failed"
	StageSkipped   StageStatus = "skipped"
)

type Stage struct {
	Name        string
	Commands    []string
	Status      StageStatus
	StartedAt   time.Time
	FinishedAt  time.Time
	Duration    time.Duration
	DependsOn   []string
}

type Pipeline struct {
	ID        string
	Branch    string
	CommitSHA string
	Stages    []Stage
	Status    PipelineStatus
	CreatedAt time.Time
}

type PipelineStatus string

const (
	PipelineQueued   PipelineStatus = "queued"
	PipelineRunning  PipelineStatus = "running"
	PipelinePassed   PipelineStatus = "passed"
	PipelineFailed   PipelineStatus = "failed"
	PipelineManual   PipelineStatus = "manual"
)

func (p *Pipeline) CanRun(stage *Stage) bool {
	for _, dep := range stage.DependsOn {
		depStage := p.findStageByName(dep)
		if depStage == nil || depStage.Status != StagePassed {
			return false
		}
	}
	return true
}

func (p *Pipeline) findStageByName(name string) *Stage {
	for i := range p.Stages {
		if p.Stages[i].Name == name {
			return &p.Stages[i]
		}
	}
	return nil
}

func (p *Pipeline) ExecuteNext() (*Stage, error) {
	for i := range p.Stages {
		stage := &p.Stages[i]
		if stage.Status == StagePending && p.CanRun(stage) {
			stage.Status = StageRunning
			stage.StartedAt = time.Now()
			return stage, nil
		}
	}
	return nil, fmt.Errorf("no stages can be executed")
}

func (p *Pipeline) MarkStageComplete(stageName string, success bool) {
	stage := p.findStageByName(stageName)
	if stage == nil {
		return
	}

	stage.FinishedAt = time.Now()
	stage.Duration = stage.FinishedAt.Sub(stage.StartedAt)

	if success {
		stage.Status = StagePassed
	} else {
		stage.Status = StageFailed
		p.Status = PipelineFailed
		return
	}

	// Check if all stages are complete
	allComplete := true
	for _, s := range p.Stages {
		if s.Status != StagePassed && s.Status != StageSkipped {
			allComplete = false
		}
	}
	if allComplete {
		p.Status = PipelinePassed
	}
}

package logging

import (
	"fmt"
	"strings"
	"sync"
	"time"
)

type LogLevel string

const (
	LevelTrace LogLevel = "TRACE"
	LevelDebug LogLevel = "DEBUG"
	LevelInfo  LogLevel = "INFO"
	LevelWarn  LogLevel = "WARN"
	LevelError LogLevel = "ERROR"
	LevelFatal LogLevel = "FATAL"
)

type LogEntry struct {
	Timestamp time.Time
	Level     LogLevel
	Service   string
	Message   string
	Fields    map[string]string
}

type LogAggregator struct {
	mu       sync.Mutex
	entries  []LogEntry
	filters  []Filter
	buffer   []LogEntry
	maxSize  int
}

func NewLogAggregator(maxSize int) *LogAggregator {
	return &LogAggregator{
		buffer: make([]LogEntry, 0, maxSize),
		maxSize: maxSize,
	}
}

func (la *LogAggregator) AddEntry(entry LogEntry) {
	la.mu.Lock()
	defer la.mu.Unlock()

	if !la.passesFilters(entry) {
		return
	}

	la.buffer = append(la.buffer, entry)
	if len(la.buffer) > la.maxSize {
		la.entries = append(la.entries, la.buffer[0])
		la.buffer = la.buffer[1:]
	}
}

func (la *LogAggregator) Query(level LogLevel, service string, since time.Time) []LogEntry {
	la.mu.Lock()
	defer la.mu.Unlock()

	var results []LogEntry
	allEntries := append(la.entries, la.buffer...)

	for _, entry := range allEntries {
		if entry.Level != level {
			continue
		}
		if service != "" && entry.Service != service {
			continue
		}
		if !entry.Timestamp.After(since) {
			continue
		}
		results = append(results, entry)
	}

	return results
}

func (la *LogAggregator) passesFilters(entry LogEntry) bool {
	for _, f := range la.filters {
		if !f.Matches(entry) {
			return false
		}
	}
	return true
}

func (la *LogAggregator) GetStats() map[string]int {
	stats := make(map[string]int)
	allEntries := append(la.entries, la.buffer...)
	for _, entry := range allEntries {
		stats[string(entry.Level)]++
	}
	return stats
}

type Filter interface {
	Matches(entry LogEntry) bool
}

type LevelFilter struct {
	MinLevel LogLevel
}

func (f LevelFilter) Matches(entry LogEntry) bool {
	levels := []LogLevel{LevelTrace, LevelDebug, LevelInfo, LevelWarn, LevelError, LevelFatal}
	for i, l := range levels {
		if l == f.MinLevel {
			for j := i; j < len(levels); j++ {
				if entry.Level == levels[j] {
					return true
				}
			}
			return false
		}
	}
	return true
}

package loadbalancer

import (
	"fmt"
	"math/rand"
	"sync"
	"time"
)

type Backend struct {
	Address    string
	Weight     int
	ActiveConn int
	TotalReq   int
	FailCount  int
	Healthy    bool
}

type Strategy interface {
	Select(backends []*Backend) *Backend
}

type WeightedRoundRobin struct {
	mu         sync.Mutex
	currentIndex int
}

func (wrr *WeightedRoundRobin) Select(backends []*Backend) *Backend {
	wrr.mu.Lock()
	defer wrr.mu.Unlock()

	healthy := make([]*Backend, 0)
	for _, b := range backends {
		if b.Healthy && b.Weight > 0 {
			healthy = append(healthy, b)
		}
	}

	if len(healthy) == 0 {
		return nil
	}

	totalWeight := 0
	for _, b := range healthy {
		totalWeight += b.Weight
	}

	wrr.currentIndex = (wrr.currentIndex + 1) % totalWeight
	current := 0
	for _, b := range healthy {
		current += b.Weight
		if wrr.currentIndex < current {
			return b
		}
	}
	return healthy[0]
}

type LeastConnections struct{}

func (lc *LeastConnections) Select(backends []*Backend) *Backend {
	var best *Backend
	for _, b := range backends {
		if !b.Healthy {
			continue
		}
		if best == nil || b.ActiveConn < best.ActiveConn {
			best = b
		}
	}
	return best
}

type RandomStrategy struct{}

func (rs *RandomStrategy) Select(backends []*Backend) *Backend {
	healthy := make([]*Backend, 0)
	for _, b := range backends {
		if b.Healthy {
			healthy = append(healthy, b)
		}
	}
	if len(healthy) == 0 {
		return nil
	}
	return healthy[rand.Intn(len(healthy))]
}

type LoadBalancer struct {
	backends []*Backend
	strategy Strategy
	mu       sync.Mutex
}

func NewLoadBalancer(strategy Strategy) *LoadBalancer {
	return &LoadBalancer{strategy: strategy}
}

func (lb *LoadBalancer) AddBackend(addr string, weight int) {
	lb.mu.Lock()
	defer lb.mu.Unlock()
	lb.backends = append(lb.backends, &Backend{
		Address: addr,
		Weight:  weight,
		Healthy: true,
	})
}

func (lb *LoadBalancer) Next() (*Backend, error) {
	lb.mu.Lock()
	defer lb.mu.Unlock()

	backend := lb.strategy.Select(lb.backends)
	if backend == nil {
		return nil, fmt.Errorf("no healthy backends available")
	}

	backend.ActiveConn++
	backend.TotalReq++
	return backend, nil
}

func (lb *LoadBalancer) Release(backend *Backend) {
	backend.ActiveConn--
}

package secrets

import (
	"crypto/rand"
	"encoding/base64"
	"sync"
	"time"
)

type Secret struct {
	Key         string
	Value       string
	CreatedAt   time.Time
	ExpiresAt   time.Time
	RotationDay int
	Version     int
}

type SecretStore struct {
	mu       sync.RWMutex
	secrets  map[string]*Secret
	history  map[string][]*Secret
}

func NewSecretStore() *SecretStore {
	return &SecretStore{
		secrets: make(map[string]*Secret),
		history: make(map[string][]*Secret),
	}
}

func (ss *SecretStore) Set(key, value string, ttl time.Duration) error {
	ss.mu.Lock()
	defer ss.mu.Unlock()

	existing, exists := ss.secrets[key]
	version := 1
	if exists {
		version = existing.Version + 1
	}

	secret := &Secret{
		Key:       key,
		Value:     value,
		CreatedAt: time.Now(),
		ExpiresAt: time.Now().Add(ttl),
		Version:   version,
	}

	if exists {
		ss.history[key] = append(ss.history[key], existing)
	}

	ss.secrets[key] = secret
	return nil
}

func (ss *SecretStore) Get(key string) (string, error) {
	ss.mu.RLock()
	defer ss.mu.RUnlock()

	secret, exists := ss.secrets[key]
	if !exists {
		return "", fmt.Errorf("secret not found: %s", key)
	}

	if time.Now().After(secret.ExpiresAt) {
		delete(ss.secrets, key)
		return "", fmt.Errorf("secret expired: %s", key)
	}

	return secret.Value, nil
}

func (ss *SecretStore) Rotate(key string, newValue string) error {
	ss.mu.Lock()
	defer ss.mu.Unlock()

	old, exists := ss.secrets[key]
	if !exists {
		return fmt.Errorf("secret not found: %s", key)
	}

	newSecret := &Secret{
		Key:       key,
		Value:     newValue,
		CreatedAt: time.Now(),
		ExpiresAt: old.ExpiresAt,
		Version:   old.Version + 1,
	}

	ss.history[key] = append(ss.history[key], old)
	ss.secrets[key] = newSecret
	return nil
}

func GenerateRandomSecret(length int) string {
	bytes := make([]byte, length)
	rand.Read(bytes)
	return base64.StdEncoding.EncodeToString(bytes)
}

package deploy

import (
	"fmt"
	"time"
)

type DeploymentStatus string

const (
	StatusBuilding    DeploymentStatus = "building"
	StatusTesting     DeploymentStatus = "testing"
	StatusStaging     DeploymentStatus = "staging"
	StatusProduction  DeploymentStatus = "production"
	StatusFailed      DeploymentStatus = "failed"
	StatusRollingBack DeploymentStatus = "rolling_back"
)

type DeploymentStage struct {
	Name        string
	Status      DeploymentStatus
	StartedAt   time.Time
	CompletedAt time.Time
	ImageTag    string
	Notes       string
}

type Deployment struct {
	ID          string
	Repository  string
	Branch      string
	CommitSHA   string
	Stages      []DeploymentStage
	CurrentStage int
	Status      DeploymentStatus
	CreatedAt   time.Time
	DeployedBy  string
}

type DeploymentPipeline struct {
	deployments map[string]*Deployment
}

func NewDeploymentPipeline() *DeploymentPipeline {
	return &DeploymentPipeline{
		deployments: make(map[string]*Deployment),
	}
}

func (dp *DeploymentPipeline) StartDeployment(repo, branch, commitSHA, deployedBy string) (*Deployment, error) {
	id := fmt.Sprintf("deploy-%d", time.Now().UnixNano())

	deployment := &Deployment{
		ID:         id,
		Repository: repo,
		Branch:     branch,
		CommitSHA:  commitSHA,
		Status:     StatusBuilding,
		CreatedAt:  time.Now(),
		DeployedBy: deployedBy,
		Stages: []DeploymentStage{
			{Name: "build", Status: StatusBuilding},
			{Name: "test", Status: StatusFailed},
			{Name: "staging", Status: StatusFailed},
			{Name: "production", Status: StatusFailed},
		},
	}

	dp.deployments[id] = deployment
	return deployment, nil
}

func (dp *DeploymentPipeline) AdvanceStage(deploymentID string) error {
	deployment := dp.deployments[deploymentID]
	if deployment == nil {
		return fmt.Errorf("deployment not found")
	}

	if deployment.CurrentStage >= len(deployment.Stages) {
		return fmt.Errorf("deployment already completed")
	}

	stage := &deployment.Stages[deployment.CurrentStage]
	stage.Status = StatusProduction
	stage.CompletedAt = time.Now()
	deployment.CurrentStage++

	if deployment.CurrentStage >= len(deployment.Stages) {
		deployment.Status = StatusProduction
	}

	return nil
}

func (dp *DeploymentPipeline) Rollback(deploymentID string) error {
	deployment := dp.deployments[deploymentID]
	if deployment == nil {
		return fmt.Errorf("deployment not found")
	}

	deployment.Status = StatusRollingBack
	for i := range deployment.Stages {
		if deployment.Stages[i].Status != StatusFailed {
			deployment.Stages[i].Status = StatusFailed
		}
	}
	return nil
}
